pub struct Field {
    pub name: &'static str,
    pub bit: u8,
    pub size: usize,
}

/// The `--fields` vocabulary (Common group only — keeps the frame to one group).
/// Authoritative: REFERENCE.md "Common Group" (ICD §2.2 Table 2.3).
pub const FIELDS: &[Field] = &[
    Field {
        name: "time",
        bit: 0,
        size: 8,
    }, // TimeStartup, u64 ns
    Field {
        name: "ypr",
        bit: 3,
        size: 12,
    }, // YawPitchRoll, 3×f32 deg
    Field {
        name: "quat",
        bit: 4,
        size: 16,
    }, // Quaternion, 4×f32
    Field {
        name: "gyro",
        bit: 5,
        size: 12,
    }, // AngularRate, 3×f32 rad/s
    Field {
        name: "accel",
        bit: 8,
        size: 12,
    }, // Accel, 3×f32 m/s^2
    Field {
        name: "imu",
        bit: 9,
        size: 24,
    }, // uncomp Accel+Gyro, 6×f32
    Field {
        name: "magpres",
        bit: 10,
        size: 20,
    }, // Mag(3×f32)+Temp+Pres
];

pub fn lookup_field(name: &str) -> Option<&'static Field> {
    FIELDS.iter().find(|f| f.name == name)
}

pub fn field_names() -> String {
    FIELDS.iter().map(|f| f.name).collect::<Vec<_>>().join(", ")
}

